ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  id: vars.taskId,
  contextId: vars.contextId,
  kind: "task",
  status: {
    state: "completed",
    message: {
      role: "agent",
      kind: "message",
      messageId: (now() as String) ++ "-" ++ vars.taskId,
      parts: [
        { kind: "text", text: (vars.finalText default "") as String }
      ]
    },
    timestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss'Z'" }
  }
}

%dw 2.0
output application/json
---
{
  model:                 (p('llm.model') default "gpt-5-mini") as String,
  max_completion_tokens: (p('llm.max_tokens') default 2048) as Number,
  messages: [
    { role: "system", content: (vars.sysPrompt default "") as String },
    { role: "user",   content: (vars.userText default "") as String }
  ]
}
